import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './hooks/useAuth';

import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import ListingsPage from './pages/ListingsPage';
import PropertyPage from './pages/PropertyPage';
import LoginPage from './pages/LoginPage';
import ApplicationPage from './pages/ApplicationPage';
import DashboardPage from './pages/DashboardPage';
import AdminPage from './pages/AdminPage';
import AIMatchPage from './pages/AIMatchPage';
import NotFoundPage from './pages/NotFoundPage';

// Stripe: only load if a real key is provided
let Elements = ({ children }) => <>{children}</>;
let stripePromise = null;
try {
  const key = process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY;
  if (key && key.startsWith('pk_')) {
    const { loadStripe } = require('@stripe/stripe-js');
    const { Elements: StripeElements } = require('@stripe/react-stripe-js');
    stripePromise = loadStripe(key);
    Elements = StripeElements;
  }
} catch (e) {
  console.warn('Stripe not configured yet.');
}

function ProtectedRoute({ children, adminOnly = false }) {
  const { user, loading } = useAuth();
  if (loading) return <div className="loading-screen">Loading...</div>;
  if (!user) return <Navigate to="/login" replace />;
  if (adminOnly && user.role !== 'admin') return <Navigate to="/" replace />;
  return children;
}

function AppRoutes() {
  return (
    <>
      <Navbar />
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/listings" element={<ListingsPage />} />
        <Route path="/properties/:id" element={<PropertyPage />} />
        <Route path="/login" element={<LoginPage />} />
        <Route path="/ai-match" element={<AIMatchPage />} />
        <Route path="/apply/:propertyId" element={<ProtectedRoute><ApplicationPage /></ProtectedRoute>} />
        <Route path="/dashboard" element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} />
        <Route path="/admin/*" element={<ProtectedRoute adminOnly><AdminPage /></ProtectedRoute>} />
        <Route path="*" element={<NotFoundPage />} />
      </Routes>
    </>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <Elements stripe={stripePromise}>
          <AppRoutes />
          <Toaster position="bottom-right" toastOptions={{ style: { fontFamily: 'inherit' } }} />
        </Elements>
      </AuthProvider>
    </BrowserRouter>
  );
}
